/* A standard RESTful design for a 'users' resource: */

// Create a user
fetch('/api/users', { method: 'POST', body: ... }); 

// Get a list of all users
fetch('/api/users', { method: 'GET' }); 

// Get ONE specific user (ID 42)
fetch('/api/users/42', { method: 'GET' }); 

// Update that specific user
fetch('/api/users/42', { method: 'PUT', body: ... }); 

// Delete that specific user
fetch('/api/users/42', { method: 'DELETE' });
